-- Web Empire 800 Tools Program — Production Wave 5
-- Adds 100 deterministic formula tools across 10 new categories.
-- Safe, idempotent upserts. No destructive deletes.

begin;

insert into public.categories(
  slug, name_ar, name_en, description, icon, style_key, sort_order, is_active
)
values
  ('saas-tools', 'أدوات SaaS', 'SaaS Tools', 'حاسبات الاشتراكات والنمو والاحتفاظ وربحية البرمجيات الخدمية.', 'cloud', 'violet', 500, true),
  ('startup-tools', 'أدوات الشركات الناشئة', 'Startup Tools', 'حاسبات الحرق والسيولة والتقييم والنمو للشركات الناشئة.', 'rocket', 'gold', 510, true),
  ('procurement-tools', 'أدوات المشتريات', 'Procurement Tools', 'حاسبات الموردين والوفورات ودورات الشراء وكفاءة الإنفاق.', 'shopping-bag', 'cyan', 520, true),
  ('quality-tools', 'أدوات إدارة الجودة', 'Quality Management Tools', 'حاسبات العيوب والعائد وإعادة العمل وجودة العمليات.', 'badge-check', 'green', 530, true),
  ('maintenance-tools', 'أدوات الصيانة', 'Maintenance Tools', 'حاسبات الاعتمادية والتوقف والتكلفة والالتزام بالصيانة.', 'wrench', 'violet', 540, true),
  ('franchise-tools', 'أدوات الامتياز التجاري', 'Franchise Tools', 'حاسبات الرسوم والعائد والأداء التشغيلي للفروع.', 'store', 'gold', 550, true),
  ('rental-business-tools', 'أدوات أعمال التأجير', 'Rental Business Tools', 'حاسبات الاستخدام والعائد والتلف والتشغيل لأعمال التأجير.', 'key-round', 'cyan', 560, true),
  ('salon-tools', 'أدوات الصالونات', 'Salon Tools', 'حاسبات المواعيد والكراسي والعمولات وهوامش خدمات الصالون.', 'scissors', 'violet', 570, true),
  ('bakery-tools', 'أدوات المخابز', 'Bakery Tools', 'حاسبات الوصفات والإنتاج والهدر والتكلفة والربحية للمخابز.', 'cake-slice', 'gold', 580, true),
  ('telecom-tools', 'أدوات الاتصالات', 'Telecom Tools', 'حاسبات المشتركين والاستخدام والتكلفة وجودة شبكات الاتصالات.', 'radio-tower', 'green', 590, true)
on conflict (slug) do update set
  name_ar = excluded.name_ar,
  name_en = excluded.name_en,
  description = excluded.description,
  icon = excluded.icon,
  style_key = excluded.style_key,
  sort_order = excluded.sort_order,
  is_active = true;

insert into public.category_translations(category_id, locale_id, name, description)
select category.id, locale.id, seed.name, seed.description
from (
  values
    ('saas-tools', 'ar', 'أدوات SaaS', 'حاسبات الاشتراكات والنمو والاحتفاظ وربحية البرمجيات الخدمية.'),
    ('saas-tools', 'en', 'SaaS Tools', 'حاسبات الاشتراكات والنمو والاحتفاظ وربحية البرمجيات الخدمية.'),
    ('startup-tools', 'ar', 'أدوات الشركات الناشئة', 'حاسبات الحرق والسيولة والتقييم والنمو للشركات الناشئة.'),
    ('startup-tools', 'en', 'Startup Tools', 'حاسبات الحرق والسيولة والتقييم والنمو للشركات الناشئة.'),
    ('procurement-tools', 'ar', 'أدوات المشتريات', 'حاسبات الموردين والوفورات ودورات الشراء وكفاءة الإنفاق.'),
    ('procurement-tools', 'en', 'Procurement Tools', 'حاسبات الموردين والوفورات ودورات الشراء وكفاءة الإنفاق.'),
    ('quality-tools', 'ar', 'أدوات إدارة الجودة', 'حاسبات العيوب والعائد وإعادة العمل وجودة العمليات.'),
    ('quality-tools', 'en', 'Quality Management Tools', 'حاسبات العيوب والعائد وإعادة العمل وجودة العمليات.'),
    ('maintenance-tools', 'ar', 'أدوات الصيانة', 'حاسبات الاعتمادية والتوقف والتكلفة والالتزام بالصيانة.'),
    ('maintenance-tools', 'en', 'Maintenance Tools', 'حاسبات الاعتمادية والتوقف والتكلفة والالتزام بالصيانة.'),
    ('franchise-tools', 'ar', 'أدوات الامتياز التجاري', 'حاسبات الرسوم والعائد والأداء التشغيلي للفروع.'),
    ('franchise-tools', 'en', 'Franchise Tools', 'حاسبات الرسوم والعائد والأداء التشغيلي للفروع.'),
    ('rental-business-tools', 'ar', 'أدوات أعمال التأجير', 'حاسبات الاستخدام والعائد والتلف والتشغيل لأعمال التأجير.'),
    ('rental-business-tools', 'en', 'Rental Business Tools', 'حاسبات الاستخدام والعائد والتلف والتشغيل لأعمال التأجير.'),
    ('salon-tools', 'ar', 'أدوات الصالونات', 'حاسبات المواعيد والكراسي والعمولات وهوامش خدمات الصالون.'),
    ('salon-tools', 'en', 'Salon Tools', 'حاسبات المواعيد والكراسي والعمولات وهوامش خدمات الصالون.'),
    ('bakery-tools', 'ar', 'أدوات المخابز', 'حاسبات الوصفات والإنتاج والهدر والتكلفة والربحية للمخابز.'),
    ('bakery-tools', 'en', 'Bakery Tools', 'حاسبات الوصفات والإنتاج والهدر والتكلفة والربحية للمخابز.'),
    ('telecom-tools', 'ar', 'أدوات الاتصالات', 'حاسبات المشتركين والاستخدام والتكلفة وجودة شبكات الاتصالات.'),
    ('telecom-tools', 'en', 'Telecom Tools', 'حاسبات المشتركين والاستخدام والتكلفة وجودة شبكات الاتصالات.')
) as seed(category_slug, locale_code, name, description)
join public.categories category on category.slug = seed.category_slug
join public.locales locale on locale.code = seed.locale_code
on conflict (category_id, locale_id) do update set
  name = excluded.name,
  description = excluded.description,
  updated_at = now();

create temporary table wave5_formula_tool_seed (
  category_slug text not null,
  slug text not null,
  title_ar text not null,
  title_en text not null,
  description_ar text not null,
  description_en text not null,
  runtime_config jsonb not null,
  input_fields jsonb not null,
  english_fields jsonb not null,
  submit_ar text not null,
  submit_en text not null,
  sort_order integer not null,
  is_featured boolean not null
) on commit drop;

insert into wave5_formula_tool_seed(
  category_slug, slug, title_ar, title_en, description_ar, description_en,
  runtime_config, input_fields, english_fields, submit_ar, submit_en,
  sort_order, is_featured
)
values
  ('saas-tools', 'monthly-recurring-revenue-calculator', 'حاسبة الإيراد الشهري المتكرر MRR', 'Monthly Recurring Revenue Calculator', 'احسب الإيراد الشهري المتكرر من العملاء ومتوسط الاشتراك.', 'Calculate MRR from customers and average monthly subscription.', '{"expression":"customers * average_monthly_revenue","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"الإيراد الشهري المتكرر","resultLabelEn":"Monthly recurring revenue","decimals":2,"showEquation":true}'::jsonb, '[{"key":"customers","label":"عدد العملاء المشتركين","type":"number","required":true,"step":1,"min":0},{"key":"average_monthly_revenue","label":"متوسط الاشتراك الشهري","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"customers","label":"Subscribed customers","type":"number","required":true,"step":1,"min":0},{"key":"average_monthly_revenue","label":"Average monthly subscription","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5000, true),
  ('saas-tools', 'annual-recurring-revenue-calculator', 'حاسبة الإيراد السنوي المتكرر ARR', 'Annual Recurring Revenue Calculator', 'حوّل MRR إلى إيراد سنوي متكرر.', 'Convert MRR to ARR.', '{"expression":"monthly_recurring_revenue * 12","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"الإيراد السنوي المتكرر","resultLabelEn":"Annual recurring revenue","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_recurring_revenue","label":"الإيراد الشهري المتكرر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_recurring_revenue","label":"Monthly recurring revenue","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5001, true),
  ('saas-tools', 'saas-customer-churn-rate-calculator', 'حاسبة معدل تسرب عملاء SaaS', 'SaaS Customer Churn Rate Calculator', 'احسب نسبة العملاء الذين ألغوا الاشتراك.', 'Calculate customer churn rate.', '{"expression":"churned_customers / starting_customers * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التسرب","resultLabelEn":"Customer churn rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"churned_customers","label":"العملاء المغادرون","type":"number","required":true,"step":1,"min":0},{"key":"starting_customers","label":"العملاء في بداية الفترة","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"churned_customers","label":"Churned customers","type":"number","required":true,"step":1,"min":0},{"key":"starting_customers","label":"Starting customers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 5002, false),
  ('saas-tools', 'saas-revenue-churn-rate-calculator', 'حاسبة تسرب الإيراد', 'Revenue Churn Rate Calculator', 'احسب الإيراد المفقود كنسبة من MRR بداية الفترة.', 'Calculate lost recurring revenue as a percentage of starting MRR.', '{"expression":"churned_mrr / starting_mrr * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"تسرب الإيراد","resultLabelEn":"Revenue churn rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"churned_mrr","label":"الإيراد الشهري المفقود","type":"number","required":true,"step":0.01,"min":0},{"key":"starting_mrr","label":"MRR بداية الفترة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"churned_mrr","label":"Churned MRR","type":"number","required":true,"step":0.01,"min":0},{"key":"starting_mrr","label":"Starting MRR","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5003, false),
  ('saas-tools', 'net-revenue-retention-calculator', 'حاسبة صافي الاحتفاظ بالإيراد NRR', 'Net Revenue Retention Calculator', 'احسب NRR بعد التوسع والتسرب والانخفاض.', 'Calculate NRR after expansion, churn, and contraction.', '{"expression":"(starting_mrr + expansion_mrr - churned_mrr - contraction_mrr) / starting_mrr * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"صافي الاحتفاظ بالإيراد","resultLabelEn":"Net revenue retention","decimals":2,"showEquation":true}'::jsonb, '[{"key":"starting_mrr","label":"MRR بداية الفترة","type":"number","required":true,"step":0.01,"min":0.01},{"key":"expansion_mrr","label":"إيراد التوسع","type":"number","required":true,"step":0.01,"min":0},{"key":"churned_mrr","label":"إيراد التسرب","type":"number","required":true,"step":0.01,"min":0},{"key":"contraction_mrr","label":"إيراد الانخفاض","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"starting_mrr","label":"Starting MRR","type":"number","required":true,"step":0.01,"min":0.01},{"key":"expansion_mrr","label":"Expansion MRR","type":"number","required":true,"step":0.01,"min":0},{"key":"churned_mrr","label":"Churned MRR","type":"number","required":true,"step":0.01,"min":0},{"key":"contraction_mrr","label":"Contraction MRR","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5004, true),
  ('saas-tools', 'saas-arpu-calculator', 'حاسبة متوسط الإيراد لكل مستخدم', 'SaaS ARPU Calculator', 'احسب متوسط الإيراد الشهري لكل مستخدم.', 'Calculate monthly average revenue per user.', '{"expression":"monthly_revenue / active_users","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"متوسط الإيراد لكل مستخدم","resultLabelEn":"Average revenue per user","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_revenue","label":"الإيراد الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"active_users","label":"المستخدمون النشطون","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"monthly_revenue","label":"Monthly revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"active_users","label":"Active users","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 5005, false),
  ('saas-tools', 'saas-cac-calculator', 'حاسبة تكلفة اكتساب عميل SaaS', 'SaaS CAC Calculator', 'احسب تكلفة اكتساب العميل.', 'Calculate customer acquisition cost.', '{"expression":"sales_marketing_cost / new_customers","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة اكتساب العميل","resultLabelEn":"Customer acquisition cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sales_marketing_cost","label":"تكلفة التسويق والمبيعات","type":"number","required":true,"step":0.01,"min":0},{"key":"new_customers","label":"العملاء الجدد","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"sales_marketing_cost","label":"Sales and marketing cost","type":"number","required":true,"step":0.01,"min":0},{"key":"new_customers","label":"New customers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 5006, false),
  ('saas-tools', 'saas-ltv-calculator', 'حاسبة قيمة عميل SaaS', 'SaaS Customer Lifetime Value Calculator', 'قدّر قيمة العميل من ARPU والهامش ومعدل التسرب.', 'Estimate customer lifetime value from ARPU, margin, and churn.', '{"expression":"arpu * gross_margin_rate / 100 / (monthly_churn_rate / 100)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"قيمة العميل التقديرية","resultLabelEn":"Estimated customer lifetime value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"arpu","label":"متوسط الإيراد الشهري للمستخدم","type":"number","required":true,"step":0.01,"min":0},{"key":"gross_margin_rate","label":"هامش الربح الإجمالي","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"monthly_churn_rate","label":"معدل التسرب الشهري","type":"number","required":true,"step":0.01,"min":0.0001,"max":100}]'::jsonb, '[{"key":"arpu","label":"Monthly ARPU","type":"number","required":true,"step":0.01,"min":0},{"key":"gross_margin_rate","label":"Gross margin rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"monthly_churn_rate","label":"Monthly churn rate","type":"number","required":true,"step":0.01,"min":0.0001,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 5007, false),
  ('saas-tools', 'saas-ltv-cac-ratio-calculator', 'حاسبة نسبة LTV إلى CAC', 'LTV to CAC Ratio Calculator', 'احسب نسبة قيمة العميل إلى تكلفة اكتسابه.', 'Calculate LTV to CAC ratio.', '{"expression":"customer_ltv / customer_cac","outputUnitAr":" مرة","outputUnitEn":" x","resultLabelAr":"نسبة LTV إلى CAC","resultLabelEn":"LTV to CAC ratio","decimals":2,"showEquation":true}'::jsonb, '[{"key":"customer_ltv","label":"قيمة العميل LTV","type":"number","required":true,"step":0.01,"min":0},{"key":"customer_cac","label":"تكلفة اكتساب العميل CAC","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"customer_ltv","label":"Customer LTV","type":"number","required":true,"step":0.01,"min":0},{"key":"customer_cac","label":"Customer CAC","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5008, false),
  ('saas-tools', 'saas-cac-payback-calculator', 'حاسبة فترة استرداد CAC', 'CAC Payback Period Calculator', 'قدّر أشهر استرداد تكلفة اكتساب العميل.', 'Estimate CAC payback period.', '{"expression":"customer_cac / (monthly_arpu * gross_margin_rate / 100)","outputUnitAr":" شهر","outputUnitEn":" months","resultLabelAr":"فترة الاسترداد","resultLabelEn":"CAC payback period","decimals":2,"showEquation":true}'::jsonb, '[{"key":"customer_cac","label":"تكلفة اكتساب العميل","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_arpu","label":"الإيراد الشهري لكل مستخدم","type":"number","required":true,"step":0.01,"min":0.01},{"key":"gross_margin_rate","label":"هامش الربح الإجمالي","type":"number","required":true,"step":0.01,"min":0.01,"max":100}]'::jsonb, '[{"key":"customer_cac","label":"Customer CAC","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_arpu","label":"Monthly ARPU","type":"number","required":true,"step":0.01,"min":0.01},{"key":"gross_margin_rate","label":"Gross margin rate","type":"number","required":true,"step":0.01,"min":0.01,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 5009, false),
  ('startup-tools', 'startup-net-burn-rate-calculator', 'حاسبة صافي الحرق الشهري', 'Startup Net Burn Rate Calculator', 'احسب صافي الحرق الشهري بعد الإيرادات.', 'Calculate monthly net burn after revenue.', '{"expression":"monthly_expenses - monthly_revenue","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"صافي الحرق","resultLabelEn":"Net burn rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_expenses","label":"المصروفات الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_revenue","label":"الإيرادات الشهرية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_expenses","label":"Monthly expenses","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_revenue","label":"Monthly revenue","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5010, true),
  ('startup-tools', 'startup-runway-calculator', 'حاسبة مدة السيولة للشركة الناشئة', 'Startup Runway Calculator', 'قدّر عدد الأشهر المتبقية قبل نفاد السيولة.', 'Estimate months of runway.', '{"expression":"cash_balance / monthly_net_burn","outputUnitAr":" شهر","outputUnitEn":" months","resultLabelAr":"مدة السيولة","resultLabelEn":"Runway","decimals":2,"showEquation":true}'::jsonb, '[{"key":"cash_balance","label":"الرصيد النقدي","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_net_burn","label":"صافي الحرق الشهري","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"cash_balance","label":"Cash balance","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_net_burn","label":"Monthly net burn","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5011, true),
  ('startup-tools', 'startup-gross-burn-calculator', 'حاسبة إجمالي الحرق', 'Startup Gross Burn Calculator', 'احسب مجموع الإنفاق الشهري قبل الإيرادات.', 'Calculate total monthly cash expenses.', '{"expression":"payroll + marketing + operations + other_expenses","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"إجمالي الحرق","resultLabelEn":"Gross burn","decimals":2,"showEquation":true}'::jsonb, '[{"key":"payroll","label":"الرواتب","type":"number","required":true,"step":0.01,"min":0},{"key":"marketing","label":"التسويق","type":"number","required":true,"step":0.01,"min":0},{"key":"operations","label":"التشغيل","type":"number","required":true,"step":0.01,"min":0},{"key":"other_expenses","label":"مصروفات أخرى","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"payroll","label":"Payroll","type":"number","required":true,"step":0.01,"min":0},{"key":"marketing","label":"Marketing","type":"number","required":true,"step":0.01,"min":0},{"key":"operations","label":"Operations","type":"number","required":true,"step":0.01,"min":0},{"key":"other_expenses","label":"Other expenses","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5012, false),
  ('startup-tools', 'post-money-valuation-calculator', 'حاسبة التقييم بعد الاستثمار', 'Post-money Valuation Calculator', 'احسب التقييم بعد إضافة الاستثمار.', 'Calculate post-money valuation.', '{"expression":"pre_money_valuation + investment_amount","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"التقييم بعد الاستثمار","resultLabelEn":"Post-money valuation","decimals":2,"showEquation":true}'::jsonb, '[{"key":"pre_money_valuation","label":"التقييم قبل الاستثمار","type":"number","required":true,"step":0.01,"min":0},{"key":"investment_amount","label":"مبلغ الاستثمار","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"pre_money_valuation","label":"Pre-money valuation","type":"number","required":true,"step":0.01,"min":0},{"key":"investment_amount","label":"Investment amount","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5013, false),
  ('startup-tools', 'investor-equity-percentage-calculator', 'حاسبة نسبة المستثمر', 'Investor Equity Percentage Calculator', 'احسب نسبة ملكية المستثمر من التقييم بعد الاستثمار.', 'Calculate investor ownership percentage.', '{"expression":"investment_amount / post_money_valuation * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة المستثمر","resultLabelEn":"Investor ownership","decimals":2,"showEquation":true}'::jsonb, '[{"key":"investment_amount","label":"مبلغ الاستثمار","type":"number","required":true,"step":0.01,"min":0},{"key":"post_money_valuation","label":"التقييم بعد الاستثمار","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"investment_amount","label":"Investment amount","type":"number","required":true,"step":0.01,"min":0},{"key":"post_money_valuation","label":"Post-money valuation","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5014, false),
  ('startup-tools', 'founder-dilution-calculator', 'حاسبة تخفيف حصة المؤسس', 'Founder Dilution Calculator', 'احسب الحصة المتبقية بعد جولة استثمار.', 'Calculate remaining founder ownership after dilution.', '{"expression":"current_founder_share * (1 - new_investor_share / 100)","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"حصة المؤسس بعد الجولة","resultLabelEn":"Founder share after round","decimals":2,"showEquation":true}'::jsonb, '[{"key":"current_founder_share","label":"حصة المؤسس الحالية","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"new_investor_share","label":"حصة المستثمر الجديد","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"current_founder_share","label":"Current founder share","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"new_investor_share","label":"New investor share","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 5015, false),
  ('startup-tools', 'startup-break-even-customers-calculator', 'حاسبة عملاء نقطة التعادل', 'Startup Break-even Customers Calculator', 'احسب عدد العملاء اللازم لتغطية التكاليف الثابتة.', 'Calculate customers needed to cover fixed costs.', '{"expression":"fixed_monthly_cost / contribution_per_customer","outputUnitAr":" عميل","outputUnitEn":" customers","resultLabelAr":"عملاء نقطة التعادل","resultLabelEn":"Break-even customers","decimals":0,"showEquation":true}'::jsonb, '[{"key":"fixed_monthly_cost","label":"التكاليف الشهرية الثابتة","type":"number","required":true,"step":0.01,"min":0},{"key":"contribution_per_customer","label":"هامش المساهمة لكل عميل","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"fixed_monthly_cost","label":"Fixed monthly cost","type":"number","required":true,"step":0.01,"min":0},{"key":"contribution_per_customer","label":"Contribution per customer","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5016, false),
  ('startup-tools', 'startup-cash-need-calculator', 'حاسبة الاحتياج النقدي', 'Startup Cash Need Calculator', 'قدّر السيولة المطلوبة لفترة تشغيل محددة.', 'Estimate cash required for a target runway.', '{"expression":"monthly_net_burn * target_months - current_cash","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الاحتياج النقدي","resultLabelEn":"Cash requirement","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_net_burn","label":"صافي الحرق الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"target_months","label":"أشهر التشغيل المستهدفة","type":"number","required":true,"step":0.01,"min":0},{"key":"current_cash","label":"السيولة الحالية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_net_burn","label":"Monthly net burn","type":"number","required":true,"step":0.01,"min":0},{"key":"target_months","label":"Target runway months","type":"number","required":true,"step":0.01,"min":0},{"key":"current_cash","label":"Current cash","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 5017, false),
