  ('startup-tools', 'startup-revenue-per-employee-calculator', 'حاسبة الإيراد لكل موظف ناشئ', 'Startup Revenue per Employee Calculator', 'احسب الإيراد السنوي لكل موظف.', 'Calculate annual revenue per employee.', '{"expression":"annual_revenue / employees","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الإيراد لكل موظف","resultLabelEn":"Revenue per employee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_revenue","label":"الإيراد السنوي","type":"number","required":true,"step":0.01,"min":0},{"key":"employees","label":"عدد الموظفين","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"annual_revenue","label":"Annual revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"employees","label":"Employees","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 5019, false),
