  ('telecom-tools', 'telecom-revenue-per-minute-calculator', 'حاسبة الإيراد لكل دقيقة اتصال', 'Revenue per Call Minute Calculator', 'احسب الإيراد لكل دقيقة اتصال.', 'Calculate revenue per call minute.', '{"expression":"voice_revenue / call_minutes","outputUnitAr":" ر.س/دقيقة","outputUnitEn":" SAR/minute","resultLabelAr":"الإيراد لكل دقيقة","resultLabelEn":"Revenue per minute","decimals":4,"showEquation":true}'::jsonb, '[{"key":"voice_revenue","label":"إيراد المكالمات","type":"number","required":true,"step":0.01,"min":0},{"key":"call_minutes","label":"دقائق الاتصال","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"voice_revenue","label":"Voice revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"call_minutes","label":"Call minutes","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5098, false),
  ('telecom-tools', 'telecom-data-usage-growth-calculator', 'حاسبة نمو استخدام البيانات', 'Data Usage Growth Calculator', 'احسب نمو استخدام البيانات بين فترتين.', 'Calculate data usage growth.', '{"expression":"(current_data_gb - previous_data_gb) / previous_data_gb * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نمو استخدام البيانات","resultLabelEn":"Data usage growth","decimals":2,"showEquation":true}'::jsonb, '[{"key":"current_data_gb","label":"الاستخدام الحالي GB","type":"number","required":true,"step":0.01,"min":0},{"key":"previous_data_gb","label":"الاستخدام السابق GB","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"current_data_gb","label":"Current data usage GB","type":"number","required":true,"step":0.01,"min":0},{"key":"previous_data_gb","label":"Previous data usage GB","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 5099, false);

do $$
declare
  v_count integer;
  v_duplicates integer;
begin
  select count(*) into v_count from wave5_formula_tool_seed;

  if v_count <> 100 then
    raise exception 'WAVE5_TOOL_COUNT_MISMATCH:%', v_count;
  end if;

  select count(*) - count(distinct slug)
  into v_duplicates
  from wave5_formula_tool_seed;

  if v_duplicates <> 0 then
    raise exception 'WAVE5_DUPLICATE_SLUGS:%', v_duplicates;
  end if;
end;
$$;

insert into public.tools(
  slug, title_ar, title_en, short_description, category_id, engine_type,
  input_schema, output_schema, runtime_config, pricing_mode, fixed_points,
  minimum_points, requires_auth, is_featured, is_active, sort_order,
  seo_title, seo_description
)
select
  seed.slug,
  seed.title_ar,
  seed.title_en,
  seed.description_ar,
  category.id,
  'formula',
  jsonb_build_object('submitLabel', seed.submit_ar, 'fields', seed.input_fields),
  jsonb_build_object('type', 'number', 'format', 'runtime'),
  seed.runtime_config,
  'free',
  0,
  0,
  false,
  seed.is_featured,
  true,
  seed.sort_order,
  seed.title_ar || ' مجانًا | أمبراطورية الويب',
  seed.description_ar
from wave5_formula_tool_seed seed
join public.categories category on category.slug = seed.category_slug
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  short_description = excluded.short_description,
  category_id = excluded.category_id,
  engine_type = excluded.engine_type,
  input_schema = excluded.input_schema,
  output_schema = excluded.output_schema,
  runtime_config = excluded.runtime_config,
  pricing_mode = excluded.pricing_mode,
  fixed_points = excluded.fixed_points,
  minimum_points = excluded.minimum_points,
  requires_auth = excluded.requires_auth,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  updated_at = now();

insert into public.tool_translations(
  tool_id, locale_id, title, short_description, seo_title, seo_description,
  prompt_template_override
)
select
  tool.id,
  locale.id,
  case when locale.code = 'ar' then seed.title_ar else seed.title_en end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  case
    when locale.code = 'ar' then seed.title_ar || ' مجانًا | أمبراطورية الويب'
    else seed.title_en || ' Free | Web Empire'
  end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  null
from wave5_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id) do update set
  title = excluded.title,
  short_description = excluded.short_description,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  prompt_template_override = null,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  field.value ->> 'key',
  field.value ->> 'label',
  nullif(field.value ->> 'placeholder', ''),
  nullif(field.value ->> 'helpText', ''),
  field.value -> 'options'
from wave5_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
cross join lateral jsonb_array_elements(
  case when locale.code = 'ar' then seed.input_fields else seed.english_fields end
) field(value)
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = excluded.placeholder,
  help_text = excluded.help_text,
  options = excluded.options,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  '__submit__',
  case when locale.code = 'ar' then seed.submit_ar else seed.submit_en end,
  null, null, null
from wave5_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  updated_at = now();

do $$
declare
  item record;
begin
  for item in
    select
      category.slug,
      count(tool.id) filter (where tool.is_active) as active_tools
    from public.categories category
    left join public.tools tool on tool.category_id = category.id
    where category.slug in (
    'saas-tools',
    'startup-tools',
    'procurement-tools',
    'quality-tools',
    'maintenance-tools',
    'franchise-tools',
    'rental-business-tools',
    'salon-tools',
    'bakery-tools',
    'telecom-tools'
    )
    group by category.slug
  loop
    if item.active_tools < 5 or item.active_tools > 50 then
      raise exception 'CATEGORY_TOOL_RANGE_VIOLATION:%:%',
        item.slug,
        item.active_tools;
    end if;
  end loop;
end;
$$;

commit;

